// Helper functions
const getCurrentUser = () => {
  try {
    const user = store?.getState()?.user || null;
    return user ? {
      id: user.id,
      email: user.email,
      name: user.name
    } : null;
  } catch (error) {
    return null;
  }
};

const getSessionId = () => {
  try {
    const session = store?.getState()?.session || null;
    return session?.id || 'unknown';
  } catch (error) {
    return 'unknown';
  }
};

// Middleware for tracking network requests
const createNetworkLogger = (fetch) => {
  return async (url, options = {}) => {
    const startTime = Date.now();
    let response;
    let requestBody = options.body;
    
    try {
      // Parse request body for logging
      if (typeof requestBody === 'string') {
        try {
          requestBody = JSON.parse(requestBody);
        } catch (e) {
          // Not JSON, keep as string
        }
      }
      
      response = await fetch(url, options);
      const endTime = Date.now();
      const duration = endTime - startTime;
      
      // Log response body
      const responseClone = response.clone();
      const responseBody = await responseClone.text();
      
      DebugLogger.logNetworkRequest(url, options.method, requestBody, responseBody, duration);
      
      return response;
    } catch (error) {
      const endTime = Date.now();
      const duration = endTime - startTime;
      DebugLogger.logError(error, `Network request to ${url}`);
      throw error;
    }
  };
};

// Patch fetch for global network logging
if (typeof fetch !== 'undefined') {
  global.fetch = createNetworkLogger(fetch);
}

// Initialize the logger
DebugLogger.init();

export default DebugLogger;